// Do not edit this file as it will be overwritten if HAMR codegen is rerun

//! Place-assertion spec functions of property `normal_mode_heat` -- one per
//! point its decoration binds (unbound points carry `true`, design D5).

#![allow(non_snake_case)]
#![allow(unused_imports)]

use data::*;
use vstd::prelude::*;

use crate::assertions::*;
use crate::system_state::SystemState;

verus! {

/** property normal_mode_heat, bound 'after oi' (place after_oi)
  *   OI orders the desired range
  */
pub open spec fn sys_assert_normal_mode_heat_after_oi(st: SystemState) -> bool
{
  sysProp_lower_is_not_higher_than_upper(st.lower_desired_tempWstatus, st.upper_desired_tempWstatus)
}

/** property normal_mode_heat, bound 'at ts_oi_done' (place post_join_1)
  *   join: carried past ts
  */
pub open spec fn sys_assert_normal_mode_heat_post_join_1(st: SystemState) -> bool
{
  sysProp_lower_is_not_higher_than_upper(st.lower_desired_tempWstatus, st.upper_desired_tempWstatus)
}

/** property normal_mode_heat, bound 'before drf' (place before_drf)
  *   branch entry: desired temp ordering carries in
  */
pub open spec fn sys_assert_normal_mode_heat_before_drf(st: SystemState) -> bool
{
  sysProp_lower_is_not_higher_than_upper(st.lower_desired_tempWstatus, st.upper_desired_tempWstatus)
}

/** property normal_mode_heat, bound 'after drf' (place after_drf)
  *   frame condition preserves desired temp ordering
  */
pub open spec fn sys_assert_normal_mode_heat_after_drf(st: SystemState) -> bool
{
  sysProp_lower_is_not_higher_than_upper(st.lower_desired_tempWstatus, st.upper_desired_tempWstatus)
}

/** property normal_mode_heat, bound 'after mri' (place after_mri)
  *   derived from MRI component contract
  */
pub open spec fn sys_assert_normal_mode_heat_after_mri(st: SystemState) -> bool
{
  (sysProp_REQ_MRI_7(st.lower_desired_tempWstatus, st.upper_desired_tempWstatus, st.reg_interface_failure) && sysProp_REQ_MRI_8(st.lower_desired_tempWstatus, st.upper_desired_tempWstatus, st.lower_desired_temp, st.upper_desired_temp, st.reg_interface_failure)) &&
    sysProp_lower_is_lower_temp(st.lower_desired_temp, st.upper_desired_temp)
}

/** property normal_mode_heat, bound 'after mrm' (place after_mrm)
  *   frame condition preserves MRI properties
  */
pub open spec fn sys_assert_normal_mode_heat_after_mrm(st: SystemState) -> bool
{
  (sysProp_REQ_MRI_7(st.lower_desired_tempWstatus, st.upper_desired_tempWstatus, st.reg_interface_failure) && sysProp_REQ_MRI_8(st.lower_desired_tempWstatus, st.upper_desired_tempWstatus, st.lower_desired_temp, st.upper_desired_temp, st.reg_interface_failure)) &&
    sysProp_lower_is_lower_temp(st.lower_desired_temp, st.upper_desired_temp)
}

/** property normal_mode_heat, bound 'after mhs' (place after_mhs)
  *   end-to-end: normal mode heat control
  */
pub open spec fn sys_assert_normal_mode_heat_after_mhs(st: SystemState) -> bool
{
  (((((st.lower_desired_tempWstatus.status == Isolette_Data_Model::ValueStatus::Valid) &&
    (st.upper_desired_tempWstatus.status == Isolette_Data_Model::ValueStatus::Valid)) &&
    (st.current_tempWstatus.status == Isolette_Data_Model::ValueStatus::Valid)) &&
    (st.regulator_mode == Isolette_Data_Model::Regulator_Mode::Normal_Regulator_Mode)) &&
    (st.current_tempWstatus.degrees < st.lower_desired_tempWstatus.degrees)) ==>
    (st.heat_control == Isolette_Data_Model::On_Off::Onn)
}

} // verus!
